import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetCommentMarkerWhenNotSet() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character commentMarker = format.getCommentMarker();
        assertNull(commentMarker, "Default format should have null comment marker");
    }

    @Test
    void testGetCommentMarkerWhenSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        Character commentMarker = format.getCommentMarker();
        assertNotNull(commentMarker, "Comment marker should not be null after setting");
        assertEquals(Character.valueOf('#'), commentMarker, "Comment marker should be '#'");
    }

    @Test
    void testGetCommentMarkerWithNull() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        Character commentMarker = format.getCommentMarker();
        assertNull(commentMarker, "Comment marker explicitly set to null should return null");
    }
}
